import{_ as r,o as t,c as a,ai as e}from"./chunks/framework.DMjte4z8.js";const u=JSON.parse('{"title":"多人游戏同步机制","description":"","frontmatter":{"title":"多人游戏同步机制","category":"advanced","updated":"2026-05-21T00:00:00.000Z","model":"openai/MiniMax-M2.7-highspeed","quality_score":0.72,"discovered_via":"manual","sources":["https://www.codeofhonor.com/blog/the-making-of-warcraft-part-3/","https://en.wikipedia.org/wiki/Warcraft_III:_Reign_of_Chaos"]},"headers":[],"relativePath":"advanced/多人游戏同步机制.md","filePath":"advanced/多人游戏同步机制.md","lastUpdated":1779353774000}'),l={name:"advanced/多人游戏同步机制.md"};function n(i,o,s,h,g,p){return t(),a("div",null,[...o[0]||(o[0]=[e('<h1 id="多人游戏同步机制" tabindex="-1">多人游戏同步机制 <a class="header-anchor" href="#多人游戏同步机制" aria-label="Permalink to “多人游戏同步机制”">​</a></h1><h2 id="什么是多人游戏同步" tabindex="-1">什么是多人游戏同步 <a class="header-anchor" href="#什么是多人游戏同步" aria-label="Permalink to “什么是多人游戏同步”">​</a></h2><p>本节将帮助你理解什么是多人游戏同步，以及它为什么是制作多人地图时必须掌握的核心概念。学完本节后，你会明白为什么多个玩家的电脑需要&quot;步调一致&quot;，以及同步失败会导致什么问题。</p><h3 id="同步的基本概念" tabindex="-1">同步的基本概念 <a class="header-anchor" href="#同步的基本概念" aria-label="Permalink to “同步的基本概念”">​</a></h3><p><strong>同步（Synchronization）</strong> 指的是在多人游戏中，所有玩家的电脑对游戏状态保持一致的过程<a href="https://www.codeofhonor.com/blog/the-making-of-warcraft-part-3/" target="_blank" rel="noreferrer">^1</a>。</p><p>你可以这样理解：想象你和朋友一起玩拼图游戏，但如果每个人都只看自己手里的碎片，而不去对照别人的，那么拼出来的图案肯定会乱七八糟。同步机制就是确保每个玩家的&quot;碎片&quot;能完美拼接在一起的规则。</p><p>在 Warcraft III 的多人游戏中，同步机制负责让所有玩家的单位位置、血量、技能状态等信息保持一致[^2]。当一名玩家移动了一个单位，其他玩家的屏幕上也会同时显示出这个单位的移动。</p><h3 id="为什么同步对多人地图很重要" tabindex="-1">为什么同步对多人地图很重要 <a class="header-anchor" href="#为什么同步对多人地图很重要" aria-label="Permalink to “为什么同步对多人地图很重要”">​</a></h3><p>如果你制作的地图支持多人联机，那么<strong>同步是生死存亡的关键</strong>：</p><ul><li><strong>避免作弊</strong>：没有同步机制，某些玩家可能利用本地计算漏洞来作弊</li><li><strong>保证公平</strong>：所有玩家必须在同一起跑线上，否则游戏体验会一团糟</li><li><strong>防止崩溃</strong>：如果各玩家的游戏状态不同步，可能导致地图崩溃或出现严重bug</li></ul><blockquote><p><strong>💡 新手提示</strong>：即使是单人地图，如果你的触发器使用了&quot;等待&quot;或&quot;周期事件&quot;等涉及时间的功能，理解同步原理也能帮助你避免很多奇怪的bug。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手常认为&quot;反正只有我自己玩，同步不重要&quot;。但实际上，即使单人地图中如果有多个电脑玩家（AI），你仍然需要考虑同步问题——否则AI单位可能表现异常。</p></blockquote><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><p>多人游戏同步的本质是<strong>让所有玩家的游戏状态保持一致</strong>。作为地图开发者，你需要时刻记住：你写的每一段触发器逻辑，都可能同时在多个玩家的电脑上运行。理解这一点，是制作稳定多人地图的第一步。</p><h2 id="魔兽争霸3的网络模型" tabindex="-1">魔兽争霸3的网络模型 <a class="header-anchor" href="#魔兽争霸3的网络模型" aria-label="Permalink to “魔兽争霸3的网络模型”">​</a></h2><p>本节将帮助你理解魔兽争霸3在多人游戏中如何实现&quot;同步&quot;——让所有玩家的画面保持一致。了解这个原理后，你在制作多人对战地图时会更容易发现和解决&quot;玩家看到的画面不一样&quot;这类问题。</p><h3 id="什么是主机与玩家" tabindex="-1">什么是主机与玩家 <a class="header-anchor" href="#什么是主机与玩家" aria-label="Permalink to “什么是主机与玩家”">​</a></h3><p>在魔兽争霸3的多人游戏中，有一个特殊的角色叫做<strong>&quot;主机&quot;（Host）</strong>，其他人则称为<strong>&quot;玩家&quot;（Client）</strong>[^2]。</p><p>你可以这样理解：</p><ul><li><strong>主机</strong>就像一间教室的老师，负责组织整场游戏的进行</li><li><strong>玩家</strong>就像学生，接收老师的指令并执行</li></ul><blockquote><p><strong>💡 新手提示</strong>：在创建多人游戏房间时，创建者默认就是主机。如果主机退出游戏，游戏房间就会关闭，其他玩家也会被踢出。</p></blockquote><h3 id="数据是如何传输的" tabindex="-1">数据是如何传输的 <a class="header-anchor" href="#数据是如何传输的" aria-label="Permalink to “数据是如何传输的”">​</a></h3><p>魔兽争霸3采用了<strong>&quot;锁步同步&quot;（Lockstep）</strong>机制，这是一种非常聪明的设计<a href="https://www.codeofhonor.com/blog/the-making-of-warcraft-part-3/" target="_blank" rel="noreferrer">^1</a>。</p><p>工作原理如下：</p><ol><li><strong>所有玩家同时执行相同的操作</strong> — 比如玩家A下达&quot;让英雄移动到某个点&quot;的指令</li><li><strong>主机收集并验证所有玩家的操作</strong> — 确保没有人作弊或出现错误</li><li><strong>统一发送&quot;下一步该做什么&quot;的指令</strong> — 所有玩家收到的是完全相同的指令<a href="https://www.codeofhonor.com/blog/the-making-of-warcraft-part-3/" target="_blank" rel="noreferrer">^1</a></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手常问&quot;为什么我明明先按了技能键，却没别人放得快？&quot;这是因为所有人的操作都要经过主机统一处理，所以并不是&quot;谁先按谁先执行&quot;，而是&quot;谁的指令先被主机收到并广播&quot;。</p></blockquote><h3 id="在地图编辑器中的实际应用" tabindex="-1">在地图编辑器中的实际应用 <a class="header-anchor" href="#在地图编辑器中的实际应用" aria-label="Permalink to “在地图编辑器中的实际应用”">​</a></h3><p>如果你要在WE（World Editor）中制作多人游戏地图，需要注意：</p><ol><li><strong>使用&quot;游戏 - 玩家&quot;相关的触发器</strong> — 这些触发器会自动处理同步逻辑</li><li><strong>避免使用仅本地有效的变量</strong> — 比如某些&quot;仅对触发玩家可见&quot;的条件，在多人游戏中可能导致不同步</li><li><strong>测试时务必用多台电脑或多个客户端</strong> — 本地测试无法发现同步问题</li></ol><h3 id="小结-1" tabindex="-1">小结 <a class="header-anchor" href="#小结-1" aria-label="Permalink to “小结”">​</a></h3><p>完成本节学习后，你应该理解了：</p><ul><li>主机负责协调所有玩家的操作</li><li>魔兽争霸3使用锁步同步确保所有人看到相同的游戏画面</li><li>制作多人地图时，需要考虑同步兼容性</li></ul><p>这为你在KK平台上开发多人对战RPG地图奠定了基础。</p><h2 id="触发器中的同步机制" tabindex="-1">触发器中的同步机制 <a class="header-anchor" href="#触发器中的同步机制" aria-label="Permalink to “触发器中的同步机制”">​</a></h2><p>在多人游戏中，所有玩家的电脑需要保持数据一致。触发器中的&quot;同步机制&quot;就是确保每个玩家看到相同游戏结果的技术。本节结束后，你将理解同步与不同步的区别，并知道在什么情况下需要使用同步动作。</p><h3 id="同步与不同步的区别" tabindex="-1">同步与不同步的区别 <a class="header-anchor" href="#同步与不同步的区别" aria-label="Permalink to “同步与不同步的区别”">​</a></h3><p>想象你和朋友视频通话，你说&quot;开始&quot;，朋友听到后同时行动——这就是&quot;同步&quot;。在魔兽争霸III的触发器中：</p><ul><li><strong>同步</strong>：这个动作会让所有玩家的游戏客户端同时执行。比如设置一个所有玩家都能看到的变量，<strong>必须用同步动作</strong>，否则只有你自己的屏幕变了，其他玩家看到的是旧数据<a href="https://www.codeofhonor.com/blog/the-making-of-warcraft-part-3/" target="_blank" rel="noreferrer">^1</a>。</li><li><strong>不同步</strong>：某些动作只需要在<strong>房主（Host）的电脑</strong>上运行，比如随机数生成器（保证大家拿到相同的随机数）。这类动作不需要&quot;同步&quot;，因为它们本来就只在主机运行。</li></ul><blockquote><p><strong>💡 新手提示</strong>：简单记忆——<strong>所有玩家都要知道的信息</strong>用同步；<strong>只需要一个人处理</strong>的逻辑不用同步。</p></blockquote><h3 id="常用的同步触发器动作" tabindex="-1">常用的同步触发器动作 <a class="header-anchor" href="#常用的同步触发器动作" aria-label="Permalink to “常用的同步触发器动作”">​</a></h3><p>在WE的触发器编辑器中，最常用的同步动作是：</p><ol><li><strong>同步变量</strong>（Sync Variable）— 将一个变量的值发送给所有玩家</li><li><strong>同步整数/实数/字符串</strong>（Sync Integer/Real/String）— 直接同步具体数值</li><li><strong>多玩家变量</strong>（Multiboard/Unit shared）— 某些系统自带同步功能</li></ol><p>在JASS脚本中，对应函数如 <code>SyncTimer()</code>、<code>SetSyncedInteger()</code> 等。</p><h3 id="何时需要同步" tabindex="-1">何时需要同步 <a class="header-anchor" href="#何时需要同步" aria-label="Permalink to “何时需要同步”">​</a></h3><p>以下情况<strong>必须同步</strong>：</p><ul><li>显示给玩家的提示信息（如&quot;第3关开始！&quot;）</li><li>改变所有玩家都能看到的游戏状态（如打开某扇门）</li><li>伤害数值、得分、金币等数值变化</li></ul><p>以下情况<strong>不需要同步</strong>：</p><ul><li>仅房主使用的临时计算变量</li><li>仅影响单个玩家私有的数据</li></ul><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忘记同步变量，导致&quot;我的屏幕显示打死了怪物，但朋友的屏幕里怪物还活着&quot;。解决方法是：每当你想让所有玩家看到同一个变化时，检查是否使用了同步动作。</p></blockquote><h3 id="小结-2" tabindex="-1">小结 <a class="header-anchor" href="#小结-2" aria-label="Permalink to “小结”">​</a></h3><p>完成以上内容后，你应该能：</p><ul><li>✅ 区分哪些触发器需要同步、哪些不需要</li><li>✅ 在触发器中使用&quot;同步变量&quot;动作</li><li>✅ 避免多人游戏中的显示不同步问题</li></ul><hr><h2 id="常见的同步问题与解决方法" tabindex="-1">常见的同步问题与解决方法 <a class="header-anchor" href="#常见的同步问题与解决方法" aria-label="Permalink to “常见的同步问题与解决方法”">​</a></h2><p>在本节中，你将了解什么是同步失败（Desync）、它为什么会破坏多人游戏体验，以及如何预防和修复常见的同步问题。学完本节后，你将能够识别潜在的同步风险，并写出更稳定的多人游戏地图。</p><h3 id="什么是同步失败-desync" tabindex="-1">什么是同步失败（Desync） <a class="header-anchor" href="#什么是同步失败-desync" aria-label="Permalink to “什么是同步失败（Desync）”">​</a></h3><p><strong>同步失败（Desync）</strong> 是指在多人游戏中，不同玩家的电脑对游戏当前状态的&quot;认知&quot;出现了分歧。想象一下：你和朋友一起玩，但你们的屏幕上显示的画面不一样——你的英雄还在原地，而朋友的屏幕上英雄已经移动了。这就是典型的同步失败。</p><p>在魔兽争霸III中，所有玩家的电脑需要就&quot;当前游戏状态&quot;达成共识<a href="https://www.codeofhonor.com/blog/the-making-of-warcraft-part-3/" target="_blank" rel="noreferrer">^1</a>。当某个玩家的电脑计算出不同的结果时，就会发生同步失败，导致游戏卡住、崩溃或出现奇怪的错误。</p><blockquote><p><strong>💡 新手提示</strong>：同步失败和&quot;卡顿&quot;不一样！卡顿是网络延迟造成的，同步失败是计算结果不同造成的。卡顿等一会儿会恢复，但同步失败往往会导致游戏直接崩溃。</p></blockquote><h3 id="导致同步失败的常见原因" tabindex="-1">导致同步失败的常见原因 <a class="header-anchor" href="#导致同步失败的常见原因" aria-label="Permalink to “导致同步失败的常见原因”">​</a></h3><ol><li><p><strong>使用&quot;本地玩家&quot;相关的触发器</strong> 如果你的触发器使用了&quot;本地玩家&quot;（Local Player）功能，不同玩家的触发器会执行不同的操作，导致游戏状态不一致。</p></li><li><p><strong>浮点数运算不一致</strong> 简单来说，浮点数就是带小数点的数字。不同电脑在计算小数时可能会产生微小的差异（比如0.00001），这些差异累积起来就会导致结果不同。</p></li><li><p><strong>随机数（随机事件）不同步</strong> 如果两个玩家同时触发了&quot;随机获取一个单位&quot;，但每台电脑独立计算随机数，就可能得到不同的结果。</p></li><li><p><strong>读取外部文件或网络数据</strong> 读取玩家电脑上不存在的文件，会导致某些玩家无法正常游戏。</p></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常在触发器里使用&quot;等待&quot;和&quot;本地玩家&quot;组合，认为这样可以创造&quot;动画效果&quot;。这几乎是100%会导致同步失败的组合！正确做法是使用&quot;预设动画&quot;动作，而不是本地脚本。</p></blockquote><h3 id="预防和修复同步问题" tabindex="-1">预防和修复同步问题 <a class="header-anchor" href="#预防和修复同步问题" aria-label="Permalink to “预防和修复同步问题”">​</a></h3><h4 id="预防方法" tabindex="-1">预防方法 <a class="header-anchor" href="#预防方法" aria-label="Permalink to “预防方法”">​</a></h4><ol><li><p><strong>避免使用&quot;本地玩家&quot;触发器</strong> 所有触发器逻辑都应该由<strong>主机玩家</strong>（创建房间的玩家）计算，然后通过&quot;广播&quot;方式同步给其他玩家。</p></li><li><p><strong>使用整数而非浮点数</strong> 在可能的情况下，使用整数进行计算。例如，将金币数量乘以100存储，用整数表示&quot;X.XX&quot;的金币。</p></li><li><p><strong>使用&quot;游戏 - 同步随机数&quot;功能</strong> 在需要随机数的地方，使用 Warcraft III 内置的同步随机数系统，而不是自己生成随机数。</p></li></ol><h4 id="修复步骤" tabindex="-1">修复步骤 <a class="header-anchor" href="#修复步骤" aria-label="Permalink to “修复步骤”">​</a></h4><ol><li><p><strong>开启同步调试模式</strong> 在测试多人游戏时，打开作弊菜单（单人游戏按Enter输入&quot;thereisnospoon&quot;类似命令），查看控制台输出的同步信息。</p></li><li><p><strong>逐一禁用触发器</strong> 如果游戏出现同步失败，尝试禁用部分触发器，找出是哪个触发器导致的问题。</p></li><li><p><strong>检查变量类型</strong> 确认所有跨网络同步的变量都使用了正确的类型（整数、字符串等），避免使用容易产生精度问题的浮点数。</p></li></ol><h3 id="小结-3" tabindex="-1">小结 <a class="header-anchor" href="#小结-3" aria-label="Permalink to “小结”">​</a></h3><p>完成以上内容后，你应该能够识别大多数常见的同步风险，并理解为什么&quot;本地玩家&quot;触发器是新手最容易犯的错误。记住：<strong>多人游戏的核心原则是——所有计算都在主机上完成，结果同步给所有玩家</strong>。遵循这个原则，你的地图同步稳定性将大幅提升。</p><h2 id="测试多人地图的方法" tabindex="-1">测试多人地图的方法 <a class="header-anchor" href="#测试多人地图的方法" aria-label="Permalink to “测试多人地图的方法”">​</a></h2><p>本节将教会你如何在 Warcraft III 世界编辑器（WE）中测试多人地图。你将学会使用<strong>局域网（LAN）连接</strong>和<strong>本地模拟</strong>两种方法来验证你的多人地图是否能正常工作。完成本节后，你就能邀请朋友一起测试你的地图了！</p><h3 id="使用局域网测试" tabindex="-1">使用局域网测试 <a class="header-anchor" href="#使用局域网测试" aria-label="Permalink to “使用局域网测试”">​</a></h3><p>局域网测试是最直接的多人游戏测试方式，可以让两台电脑直接连接进行测试。</p><ol><li><p><strong>第一步：准备测试环境</strong> — 确保你的两台电脑连接到同一个路由器或交换机上（也就是同一个网络）。[^2]</p></li><li><p><strong>第二步：打开 Warcraft III</strong> — 在第一台电脑（作为&quot;主机&quot;）上启动 Warcraft III，进入主菜单。</p></li><li><p><strong>第三步：创建主机游戏</strong> — 在主菜单中选择「局域网模式（LAN）」，然后点击「创建游戏」。输入你的地图名称，选择地图文件后，等待其他玩家加入。</p></li><li><p><strong>第四步：加入游戏</strong> — 在第二台电脑（作为&quot;客户端&quot;）上启动 Warcraft III，同样进入「局域网模式」，你应该能看到主机创建的游戏，点击「加入」即可。</p></li><li><p><strong>第五步：验证同步</strong> — 两台电脑都进入游戏后，测试你地图中的多人功能（如多人触发器、单位同步等），观察是否存在延迟或不同步的问题。</p></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忽略防火墙设置！如果第二台电脑看不到主机创建的游戏，请检查两台电脑的 Windows 防火墙是否允许 Warcraft III 通过。解决方法是在防火墙设置中添加 Warcraft III 为例外程序。</p></blockquote><blockquote><p><strong>💡 新手提示</strong>：如果你只有一台电脑，也可以通过创建两个 Warcraft III 快捷方式来模拟多人游戏——第一个窗口创建游戏，第二个窗口加入，这样就能在单机上测试多人功能了！</p></blockquote><h3 id="本地模拟多人游戏" tabindex="-1">本地模拟多人游戏 <a class="header-anchor" href="#本地模拟多人游戏" aria-label="Permalink to “本地模拟多人游戏”">​</a></h3><p>有时候身边没有第二台电脑，或者网络环境不允许，这时可以使用本地模拟的方法来测试。</p><ol><li><p><strong>第一步：启动第一个游戏实例</strong> — 正常启动 Warcraft III 并进入你的地图，作为第一玩家进行操作。</p></li><li><p><strong>第二步：启动第二个游戏实例</strong> — 右键点击桌面上的 Warcraft III 快捷方式，选择「在新窗口中打开」或使用命令行参数启动第二个实例。不同版本的 Warcraft III 可能需要不同的启动方式，你可以尝试按住 Shift 键的同时双击快捷方式。</p></li><li><p><strong>第三步：设置游戏参数</strong> — 在第二个实例中，同样进入你的地图，选择一个不同的玩家位置。这样你就可以在一台电脑上同时控制多个玩家视角。</p></li><li><p><strong>第四步：测试交互逻辑</strong> — 通过切换窗口，模拟两个玩家的操作，测试触发器中涉及多玩家的逻辑是否正常运行。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：使用 Alt+Tab 快捷键可以快速在两个游戏窗口之间切换，这会让模拟测试更加顺畅！</p></blockquote><h3 id="小结-4" tabindex="-1">小结 <a class="header-anchor" href="#小结-4" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该已经掌握了两种测试多人地图的方法：<strong>局域网测试</strong>适合有真实网络环境的场景，能最真实地反映多人游戏的同步情况；<strong>本地模拟</strong>则适合快速验证基本的双人逻辑，即使身边没有第二台电脑也能进行初步测试。建议先使用本地模拟进行快速调试，确认基本功能正常后，再使用局域网邀请朋友做最终测试。</p><h2 id="进阶同步技巧" tabindex="-1">进阶同步技巧 <a class="header-anchor" href="#进阶同步技巧" aria-label="Permalink to “进阶同步技巧”">​</a></h2><p>本节将学习如何优化多人游戏的网络同步性能，并处理一些复杂的同步场景。学完本节后，你将能够让你的地图在多人对战时运行得更流畅，减少卡顿和不同步的问题。</p><h3 id="优化同步性能" tabindex="-1">优化同步性能 <a class="header-anchor" href="#优化同步性能" aria-label="Permalink to “优化同步性能”">​</a></h3><p>优化同步性能的核心是<strong>减少需要传输的数据量</strong>。就像 Warcraft 的早期开发者在设计多人模式时，就考虑了如何&quot;最小化网络上需要传输的数据量&quot;<a href="https://www.codeofhonor.com/blog/the-making-of-warcraft-part-3/" target="_blank" rel="noreferrer">^1</a>。数据传得越少，游戏就越流畅。</p><ol><li><p><strong>第一步：识别高频同步的触发器</strong> — 在 World Editor 中打开你的地图，按 <code>F4</code> 打开触发器编辑器。找到那些在每个游戏周期都在执行的触发器（每几秒或每0.1秒执行一次的）。这些触发器是同步优化的重点对象<a href="https://www.codeofhonor.com/blog/the-making-of-warcraft-part-3/" target="_blank" rel="noreferrer">^1</a>。</p></li><li><p><strong>第二步：将只影响本机玩家的逻辑移到本地执行</strong> — 在触发器中，用&quot;玩家 - 玩家组遍历&quot;这样的动作时，想想这个动作是否真的需要所有玩家都收到。比如显示特效给特定玩家看，只需要那个玩家的客户端计算即可。</p></li><li><p><strong>第三步：使用本地变量替代全局变量广播</strong> — 全局变量修改会自动同步给所有玩家，这会消耗网络带宽。如果某个变量只需要本机使用，就不要定义为全局变量，改用本地变量（JASS 中的 <code>local</code> 关键字）。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：优化同步性能的关键是&quot;能本地算的就不传输&quot;。你可以这样理解：让每个玩家的电脑做更多的计算工作，而不是把所有计算都推到网络上传输。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手常犯的错误是把所有变量都定义为全局变量，这会导致每次修改变量时都要在网络上广播数据，造成严重的延迟。解决方法是把那些&quot;只有我自己需要知道&quot;的变量改成局部变量。</p></blockquote><h3 id="复杂的同步场景处理" tabindex="-1">复杂的同步场景处理 <a class="header-anchor" href="#复杂的同步场景处理" aria-label="Permalink to “复杂的同步场景处理”">​</a></h3><p>复杂的同步场景包括：多个玩家同时触发同一个事件、单位状态在网络中的延迟表现、以及随机数的同步问题。</p><ol><li><p><strong>第一步：理解&quot;权威性&quot;概念</strong> — 在多人游戏中，需要有一个&quot;权威&quot;来决定事件的最终结果。通常这个权威是触发这个事件的玩家，或者由地图设计者指定一个服务器玩家（比如主机玩家）。所有其他玩家都必须接受权威玩家的判定结果。</p></li><li><p><strong>第二步：为每个事件指定执行权威</strong> — 在你的触发器中，当一个事件被触发时，明确记录是哪个玩家触发的。后续的逻辑判断都以触发玩家的结果为准，而不是每个玩家本地计算的结果。</p></li><li><p><strong>第三步：处理延迟补偿</strong> — 网络延迟是客观存在的。当玩家A的操作需要0.2秒才能到达玩家B的电脑时，玩家B需要&quot;等待&quot;这段时间。常见的做法是：在本地先显示操作效果（乐观更新），等服务器确认后再纠正（悲观更新）。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：如果你的地图出现了&quot;不同步&quot;问题（玩家看到的画面不一致），首先检查的就是触发器中是否有明确指定权威玩家。不同步通常是因为每个玩家都在独立计算结果。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手在设计多人触发时容易遗漏&quot;谁来判定&quot;这个问题，导致每个玩家的客户端计算出不同的结果。解决方法是在触发器的最开头就明确设置一个&quot;执行权威玩家&quot;变量。</p></blockquote><h3 id="小结-5" tabindex="-1">小结 <a class="header-anchor" href="#小结-5" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能够识别出哪些触发器需要重点优化，并学会使用局部变量来减少网络传输。同时，你也掌握了为复杂事件指定权威玩家的方法，这能有效避免不同步问题。记住：<strong>优化同步是一个反复测试、调整的过程</strong>，建议每次修改后都进行一次多人测试，观察是否出现延迟或不同步现象。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p><a href="https://www.codeofhonor.com/blog/the-making-of-warcraft-part-3/" target="_blank" rel="noreferrer">^1</a>: <a href="https://www.codeofhonor.com/blog/the-making-of-warcraft-part-3/" target="_blank" rel="noreferrer">The making of Warcraft part 3 | Code of Honor</a> — accessed 2026-05-21 [^2]: <a href="https://en.wikipedia.org/wiki/Warcraft_III:_Reign_of_Chaos" target="_blank" rel="noreferrer">Warcraft III: Reign of Chaos - Wikipedia</a> — accessed 2026-05-21</p>',98)])])}const d=r(l,[["render",n]]);export{u as __pageData,d as default};
